Currently the connector hard-codes its configuration inside the `CruxOMRSRepositoryConnector` class. We should really allow the configuration to be passed in as part of the admin services that configure the connection itself.

This should just require some simple mapping between certain pre-defined keys / map structure and an appropriate configuration, eg.:

```
{
 "crux/index-store": {
 "kv-store": {
 "crux/module": "crux.rocksdb/->kv-store",
 "db-dir": "data/servers/crux/rdb-index"
 }
 },
 "crux/document-store": {
 "kv-store": {
 "crux/module": "crux.rocksdb/->kv-store",
 "db-dir": "data/servers/crux/rdb-docs"
 }
 },
 "crux/tx-log": {
 "crux/module": "crux.kafka/->tx-log",
 "kafka-config": {
 "bootstrap-servers": "localhost:9092"
 },
 "tx-topic-opts": {
 "topic-name": "crux-tx-log"
 },
 "poll-wait-duration": "PT1S"
 }
}
```
